import{_ as e,o as r,c as t,ag as l}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"从输入 URL 到页面呈现，整个过程发生了什么？","description":"","frontmatter":{"title":"从输入 URL 到页面呈现，整个过程发生了什么？","difficulty":"hard","tags":["浏览器","网络","渲染","DNS","TCP","HTTPS"],"estimate":30},"headers":[],"relativePath":"domains/browser/qa/qa-01-url-to-page.md","filePath":"domains/browser/qa/qa-01-url-to-page.md","lastUpdated":1783504823000}'),i={name:"domains/browser/qa/qa-01-url-to-page.md"};function s(n,o,a,d,c,g){return r(),t("div",null,[...o[0]||(o[0]=[l('<h1 id="问答-01-高级-从输入-url-到页面呈现-整个过程发生了什么" tabindex="-1">问答 01（高级）：从输入 URL 到页面呈现，整个过程发生了什么？ <a class="header-anchor" href="#问答-01-高级-从输入-url-到页面呈现-整个过程发生了什么" aria-label="Permalink to &quot;问答 01（高级）：从输入 URL 到页面呈现，整个过程发生了什么？&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>经典问题：在浏览器地址栏输入 <code>https://example.com</code> 并回车，直到页面完全呈现，浏览器和网络层做了哪些事？请覆盖 DNS、TCP、HTTPS、HTTP、渲染以及白屏 / FCP / LCP 的过渡。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p>整体分四个大阶段：<strong>导航（Navigation）→ 网络（Network）→ 渲染（Rendering）→ 交互（Interaction）</strong>。</p><p><strong>1. URL 解析与导航准备</strong></p><ul><li>浏览器进程解析 URL，判断协议（http/https/data/blob/file）、host、port、path、query、hash。</li><li>检查 HSTS、Service Worker 拦截（有则可能直接走本地缓存）。</li><li>检查 <strong>HTTP 缓存</strong>（强缓存命中直接返回，本地 200，不发请求）。</li><li>若未命中或需要协商，进入 DNS 解析。</li></ul><p><strong>2. DNS 解析</strong></p><ul><li>顺序：浏览器 DNS 缓存 → OS 缓存 → hosts 文件 → 本地 DNS（LDNS）→ 根域名 → 顶级域 → 权威域名。</li><li>结果得到目标 IP。生产环境常见优化：<code>dns-prefetch</code>、HTTPDNS、CDN 边缘解析。</li></ul><p><strong>3. 建立连接</strong></p><ul><li>TCP：<strong>三次握手</strong>（SYN → SYN+ACK → ACK）建立可靠通道。</li><li>若是 HTTPS：在 TCP 之上做 <strong>TLS 握手</strong>。 <ul><li>TLS 1.2 通常 2-RTT，交换 ClientHello / ServerHello / 证书 / 密钥交换 / Finished。</li><li>TLS 1.3 简化为 1-RTT，甚至 0-RTT（session resumption）。</li></ul></li><li>HTTP/2 会协商 ALPN 复用一条 TCP 连接多路复用请求。</li><li>HTTP/3 直接在 UDP 上跑 QUIC，把 TCP+TLS 合并为 1-RTT（甚至 0-RTT）。</li></ul><p><strong>4. 发送 HTTP 请求 + 接收响应</strong></p><ul><li>浏览器构造请求行 + Header（Cookie、Referer、User-Agent、Accept、Accept-Encoding 等）+ Body（GET 通常无）。</li><li>服务器返回状态行 + Header + Body。</li><li>若是 304，浏览器读本地磁盘缓存。若是 3xx，重定向再来一次。</li></ul><p><strong>5. 渲染主线程处理响应</strong></p><ul><li><strong>HTML 解析</strong>：字节 → 字符 → Token → Node → DOM 树。</li><li>遇到 <code>&lt;link rel=&quot;stylesheet&quot;&gt;</code>：并行请求 CSS，CSS 会阻塞渲染（不阻塞 DOM 构建，但阻塞 CSSOM → 阻塞后续 script 执行）。</li><li>遇到 <code>&lt;script&gt;</code>：默认阻塞 DOM 构建（下载并执行），可用 <code>async</code> / <code>defer</code> / <code>type=&quot;module&quot;</code> 改变时机。</li><li>构建 <strong>CSSOM</strong>，与 DOM 结合成 <strong>Render Tree</strong>（不含 <code>display:none</code> 节点，含伪元素）。</li><li><strong>Layout（回流）</strong>：计算每个盒子的位置和尺寸。</li><li><strong>Paint（重绘）</strong>：把节点画成像素图层。</li><li><strong>Composite（合成）</strong>：GPU 合成多个层，栅格化提交给屏幕。</li></ul><p><strong>6. 白屏 → FCP → LCP 的过渡</strong></p><ul><li><strong>白屏</strong>：从导航开始到浏览器第一次绘制之间，此时只有背景色，用户看到白屏。原因：DNS / TCP / TLS / 首字节 TTFB / CSS 阻塞 / 首屏 JS 执行慢。</li><li><strong>FCP（First Contentful Paint）</strong>：绘制了第一个文本 / 图像 / SVG 节点，用户第一次看到「有东西了」。</li><li><strong>LCP（Largest Contentful Paint）</strong>：视口内最大的可见元素（通常是首屏图 / 大段文本 / 视频封面）绘制完成的时间。是「主要内容加载完成」的度量。</li><li><strong>TTI / INP</strong>：主线程空闲、可以稳定响应用户输入。</li></ul><p><strong>7. 交互阶段</strong></p><ul><li>事件循环处理点击、滚动、输入。</li><li>后续懒加载资源、埋点上报、<code>prefetch</code> 下一页。</li></ul><h2 id="追问-1-js-与-css-分别在什么时机阻塞渲染-如何减小影响" tabindex="-1">追问 1：JS 与 CSS 分别在什么时机阻塞渲染？如何减小影响？ <a class="header-anchor" href="#追问-1-js-与-css-分别在什么时机阻塞渲染-如何减小影响" aria-label="Permalink to &quot;追问 1：JS 与 CSS 分别在什么时机阻塞渲染？如何减小影响？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>CSS</strong>：不阻塞 HTML 解析，但<strong>阻塞渲染</strong>（Render Tree 需要 CSSOM），也<strong>阻塞后续 script 执行</strong>（因为脚本可能读样式）。因此把关键 CSS inline、非关键 CSS 用 <code>media</code> 属性或 <code>preload</code> 异步加载。</li><li><strong>同步 script</strong>：<strong>阻塞</strong> HTML 解析和渲染（下载 + 解析 + 执行都串行）。</li><li><strong><code>defer</code> script</strong>：并行下载，<strong>在 DOMContentLoaded 前、按顺序</strong>执行，不阻塞解析。首屏推荐。</li><li><strong><code>async</code> script</strong>：并行下载，<strong>下载完立即执行</strong>（可能中断解析），执行顺序不确定。适合独立第三方脚本（埋点）。</li><li>通用手段：拆包、代码分割、按需加载、preload 关键资源、把大脚本移到底部或用 worker。</li></ul><h2 id="追问-2-一次导航中如果同时命中强缓存和协商缓存-会怎么走" tabindex="-1">追问 2：一次导航中如果同时命中强缓存和协商缓存，会怎么走？ <a class="header-anchor" href="#追问-2-一次导航中如果同时命中强缓存和协商缓存-会怎么走" aria-label="Permalink to &quot;追问 2：一次导航中如果同时命中强缓存和协商缓存，会怎么走？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>强缓存优先</strong>。浏览器先看 <code>Cache-Control: max-age=N</code> 或 <code>Expires</code>，若未过期直接命中，<strong>不发请求</strong>，状态显示为 <code>200 (from disk cache / memory cache)</code>。</li><li>强缓存失效后才进入协商缓存：带上 <code>If-None-Match: &lt;etag&gt;</code> 和 <code>If-Modified-Since: &lt;date&gt;</code> 请求服务器。</li><li>命中协商则返回 <code>304 Not Modified</code>，浏览器用本地缓存 body；未命中返回 <code>200</code> + 新 body。</li><li>特殊：<code>Cache-Control: no-cache</code> 意为「跳过强缓存，直接走协商」；<code>no-store</code> 意为「完全不缓存」。</li></ul><h2 id="追问-3-为什么第一次访问某网站很慢-之后几次就快很多-涉及哪些「连接复用」" tabindex="-1">追问 3：为什么第一次访问某网站很慢，之后几次就快很多？涉及哪些「连接复用」？ <a class="header-anchor" href="#追问-3-为什么第一次访问某网站很慢-之后几次就快很多-涉及哪些「连接复用」" aria-label="Permalink to &quot;追问 3：为什么第一次访问某网站很慢，之后几次就快很多？涉及哪些「连接复用」？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>首访要付出：DNS 解析、TCP 握手、TLS 握手、下载全部资源、CSS/JS 解析编译、字体、图片。</li><li>二次访问受益于： <ul><li><strong>DNS 缓存</strong>（几分钟到几小时）。</li><li><strong>TCP 连接复用</strong>（HTTP/1.1 Keep-Alive、HTTP/2 多路复用一条连接、HTTP/3 连接迁移）。</li><li><strong>TLS session resumption</strong>（Session ID / Session Ticket / TLS 1.3 PSK），减少 1 个 RTT。</li><li><strong>HTTP 缓存</strong>（强缓存直接命中，协商缓存节省 body 传输）。</li><li><strong>V8 code cache</strong>（脚本已经编译过）、字体缓存、Service Worker 预缓存。</li></ul></li><li>生产化技巧：Preconnect、Early Hints (<code>103</code>)、HTTP/2 Server Push（已逐渐被废弃）、HTTP/3 0-RTT。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://hpbn.co/" target="_blank" rel="noreferrer">High Performance Browser Networking</a>：URL 到页面全链路：DNS、TCP、TLS、HTTP、渲染</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/Performance/How_browsers_work" target="_blank" rel="noreferrer">MDN: How browsers work</a>：浏览器导航、解析与渲染概览</li><li><a href="https://developer.chrome.com/blog/inside-browser-part1" target="_blank" rel="noreferrer">Inside look at modern browser</a>：Chromium 多进程架构系列</li></ul>',31)])])}const S=e(i,[["render",s]]);export{p as __pageData,S as default};
